const DROP_ACARS_LABELS = ['']; /* _d */
function looksLikeAirframesEvent(v) {
  return v && typeof v === 'object' && (v.id || v.timestamp || v.station || v.airframe || v.source);
}

function extractEvent(v) {
  if (!v || typeof v !== 'object') return {};
  if (looksLikeAirframesEvent(v)) return v;
  for (const k of ['payload', 'event', 'message', 'data']) {
    if (looksLikeAirframesEvent(v[k])) return v[k];
  }
  return v;
}

function response(payload) {
  return {
    req: msg.req,
    res: msg.res,
    statusCode: 200,
    headers: { 'content-type': 'application/json' },
    payload
  };
}

// ── Extract & normalize ────────────────────────────────────────────
const envelope = msg.payload || {};
const event = extractEvent(envelope);

const labelRaw = String(event.label || '').trim();
const label = labelRaw.toLowerCase();

if (DROP_ACARS_LABELS.includes(label)) {
  return [null, null,
    response({ ok: true, dropped: true, reason: 'acars_label', label: event.label, id: event.id }),
    null, null, null
  ];
}

const flight = event.flight || {};
const airframe = event.airframe || {};
const station = event.station || {};
const now = new Date().toISOString();

const normalized = {
  received_at: now,
  id: event.id,
  timestamp: event.timestamp || event.created_at || now,
  station: station.ident,
  country: station.country_code,
  flight: flight.flight_iata || flight.flight_icao || flight.flight,
  airframe_icao: airframe.icao,
  tail: airframe.tail || event.tail,
  military: airframe.military,
  source: event.source,
  source_type: event.source_type,
  frequency: event.frequency,
  label: event.label,
  mode: event.mode,
  text: event.text,
  decoded: event.decoded,
  libacars: event.libacars,
  acars_decoded: event.acars_decoded,
  raw: event
};

// ── Seed flow cache ────────────────────────────────────────────────
let recent = flow.get('airframes_recent') || [];
const key = normalized.id || (normalized.timestamp + '-' + normalized.station + '-' + normalized.text);
recent = recent.filter(e => {
  const k = e.id || (e.timestamp + '-' + e.station + '-' + e.text);
  return k !== key;
});
recent.unshift(normalized);
recent = recent.slice(0, 500);
flow.set('airframes_recent', recent);

// ── Outputs ────────────────────────────────────────────────────────
// Output 1: Debug
const debugMsg = { payload: normalized };

// Output 2: Write base record to JSONL (ONE write per ingested message)
const fileMsg = { payload: JSON.stringify(normalized) };

// Output 3: HTTP response
const responseMsg = response({ ok: true, id: normalized.id, received_at: normalized.received_at });

const acarsDecoderMsg = (normalized.label && normalized.text) ? { payload: normalized, normalized } : null;

// Output 6: API lookup (validación estricta ICAO)
const apiLookupMsg = (
  normalized.airframe_icao && /^[A-F0-9]{6}$/i.test(normalized.airframe_icao)
) ? { payload: normalized, normalized } : null;

return [debugMsg, fileMsg, responseMsg, acarsDecoderMsg, apiLookupMsg];

// FIX: No longer writes to file directly.
// Calls airframes-merge-and-persist which does a deep-merge append.

const normalized = msg.normalized || msg.payload || {};
const event      = normalized.raw || {};

const label  = String(normalized.label  || event.label  || '').trim().toUpperCase();
const text   = String(normalized.text   || event.text   || '').trim();
const tail   = String(normalized.tail   || event.tail   || '').trim();
const flight = String(normalized.flight || '').trim();

if (!label || !text) return null;

let decoded = null;
try {
  const { MessageDecoder } = AcarsDecoder;
  const decoder = new MessageDecoder();
  const msgObj = { label, text };
  if (tail)   msgObj.tail   = tail;
  if (flight) msgObj.flight = flight;
  decoded = decoder.decode(msgObj);
} catch (err) {
  node.warn('acars-decoder error [' + label + ']: ' + (err.message || String(err)));
}

if (!decoded) return null;

const base = msg.normalized || {};

// Update flow cache
let recent = flow.get('airframes_recent') || [];
const key = base.id || (base.timestamp + '-' + base.station + '-' + base.text);
const existing = recent.find(e => {
  const k = e.id || (e.timestamp + '-' + e.station + '-' + e.text);
  return k === key;
});

const enriched = {
  ...(existing || base),
  acars_decoded: {
    ok: true,
    label,
    decoded,
    decoder: 'acars-decoder-typescript'
  }
};

recent = recent.filter(e => {
  const k = e.id || (e.timestamp + '-' + e.station + '-' + e.text);
  return k !== key;
});
recent.unshift(enriched);
recent = recent.slice(0, 500);
flow.set('airframes_recent', recent);

// Pass to merge-and-persist (NOT directly to file)
return { payload: enriched, normalized: enriched };

const normalized = msg.normalized || msg.payload || {};
const icao = String(normalized.airframe_icao || '').trim().toUpperCase();

if (!icao || !/^[A-F0-9]{6}$/.test(icao)) return null;

msg.url       = 'https://api.airframes.io/airframes/icao/' + encodeURIComponent(icao);
msg.method    = 'GET';
msg.headers   = { accept: 'application/json' };
msg.normalized = normalized;
msg.icao       = icao;

return msg;

// FIX: No longer writes to file directly.
// Calls airframes-merge-and-persist which does a deep-merge append.

const normalized = msg.normalized || {};
const icao    = msg.icao || normalized.airframe_icao;
const base    = msg.normalized || {};
const apiData = msg.payload || {};

// Update flow cache
let recent = flow.get('airframes_recent') || [];
const key = base.id || (base.timestamp + '-' + base.station + '-' + base.text);
const existing = recent.find(e => {
  const k = e.id || (e.timestamp + '-' + e.station + '-' + e.text);
  return k === key;
});

const enriched = {
  ...(existing || base),
  airframes_api: {
    ...apiData,
    icao,
    fetched_at: new Date().toISOString(),
    ok: msg.statusCode < 400
  }
};

recent = recent.filter(e => {
  const k = e.id || (e.timestamp + '-' + e.station + '-' + e.text);
  return k !== key;
});
recent.unshift(enriched);
recent = recent.slice(0, 500);
flow.set('airframes_recent', recent);

// Pass to merge-and-persist (NOT directly to file)
return { payload: enriched, normalized: enriched };

// ─────────────────────────────────────────────────────────────────
// MERGE-AND-PERSIST
// Called by: libacars-parse, acars-decoder, api-auto-enrich
//
// Purpose: append an "enrichment patch" line to the JSONL file.
// The Build-events reader will deep-merge all lines sharing the
// same key, so no decoder output is ever overwritten.
//
// Each line written here is a partial record that contains:
//   _key        – dedup key (id or timestamp-station-text)
//   _patch_type – which decoder produced this line ('libacars' | 'acars' | 'api')
//   <enrichment field> – only the new data (libacars / acars_decoded / airframes_api)
//
// The base record (all normalized fields) is already written by
// the normalize node → airframes-file, so we only persist the delta.
// ─────────────────────────────────────────────────────────────────

const enriched = msg.normalized || msg.payload || {};

const key = enriched.id ||
  (enriched.timestamp + '-' + enriched.station + '-' + enriched.text);

// Determine which new field is present and build a minimal patch
let patchType = 'unknown';
const patch = { _key: key, _patch: true };

if (enriched.libacars) {
  patchType = 'libacars';
  patch.libacars = enriched.libacars;
}
if (enriched.acars_decoded) {
  patchType = patchType === 'unknown' ? 'acars' : patchType + '+acars';
  patch.acars_decoded = enriched.acars_decoded;
}
if (enriched.airframes_api) {
  patchType = patchType === 'unknown' ? 'api' : patchType + '+api';
  patch.airframes_api = enriched.airframes_api;
}

// Only write if there is something to persist
if (patchType === 'unknown') return null;

patch._patch_type = patchType;

return { payload: JSON.stringify(patch) };

// ─────────────────────────────────────────────────────────────────
// BUILD EVENTS JSON  (deep-merge strategy)
//
// The JSONL file now contains two kinds of lines:
//   1. Base records   – written by normalize (no _patch field)
//   2. Patch records  – written by merge-and-persist (_patch: true)
//
// We read ALL lines, group by key, then deep-merge base + all patches
// in arrival order so no enrichment field is ever lost.
// ─────────────────────────────────────────────────────────────────

function normalizeRecord(record) {
  if (!record || typeof record !== 'object') return null;
  // Already normalized shape
  if (record.raw || record.received_at || record.airframe_icao) return record;

  // Legacy shape from older code (nested flight/airframe/station)
  const flight   = record.flight   || {};
  const airframe = record.airframe || {};
  const station  = record.station  || {};

  return {
    received_at:   record.received_at,
    id:            record.id,
    timestamp:     record.timestamp || record.created_at,
    station:       station.ident,
    country:       station.country_code,
    flight:        flight.flight_iata || flight.flight_icao || flight.flight,
    airframe_icao: airframe.icao,
    tail:          airframe.tail || record.tail,
    military:      airframe.military,
    source:        record.source,
    source_type:   record.source_type,
    frequency:     record.frequency,
    label:         record.label,
    mode:          record.mode,
    text:          record.text,
    raw:           record
  };
}

function recordKey(r) {
  return r.id || (r.timestamp + '-' + r.station + '-' + r.text);
}

const limit = Math.max(
  1,
  Math.min(parseInt(msg.req?.query?.limit || '100', 10) || 100, 2000)
);

const lines = String(msg.payload || '')
  .split(/\r?\n/)
  .filter(Boolean);

// Pass 1 – collect all records in file order
const bases   = new Map();   // key → base record
const patches = new Map();   // key → array of patch objects

for (const line of lines) {
  try {
    const parsed = JSON.parse(line);
    if (!parsed || typeof parsed !== 'object') continue;

    if (parsed._patch) {
      // Patch line – store by _key
      const k = parsed._key;
      if (!k) continue;
      if (!patches.has(k)) patches.set(k, []);
      patches.get(k).push(parsed);
    } else {
      // Base line
      const norm = normalizeRecord(parsed);
      if (!norm) continue;
      const k = recordKey(norm);
      // Later base lines overwrite earlier ones (re-ingestion edge case)
      bases.set(k, norm);
    }
  } catch (_) {
    // ignore corrupt lines
  }
}

// Pass 2 – merge patches onto bases and collect latest `limit` keys
// We want the most-recent `limit` unique keys. Since bases is a Map
// (insertion-order), iterate it in reverse.
const baseKeys  = [...bases.keys()];
const selected  = baseKeys.slice(-limit).reverse(); // newest first

const results = [];
for (const k of selected) {
  const base   = bases.get(k);
  const pList  = patches.get(k) || [];

  // Deep merge: apply patches in order
  let merged = { ...base };
  for (const p of pList) {
    if (p.libacars)      merged.libacars      = p.libacars;
    if (p.acars_decoded) merged.acars_decoded = p.acars_decoded;
    if (p.airframes_api) merged.airframes_api = p.airframes_api;
  }
  results.push(merged);
}

msg.headers = {
  'content-type': 'application/json; charset=utf-8',
  'cache-control': 'no-store'
};
msg.payload = JSON.stringify(results);
return msg;

// FIX: stats now account for base + patch lines separately.
// Patch lines (_patch:true) are NOT counted as messages but DO
// contribute to the decoded/api counters.

const content = String(msg.payload||'');
const lines   = content.split(/\r?\n/).filter(l => l.trim());

let validJson = 0, invalidJson = 0;
let acarsDecodedCount = 0, libacarsDecodedCount = 0, apiCachedCount = 0;
const byLabel = {}, bySource = {};
let latestTimestamp = null, earliestTimestamp = null;

// Track which keys already have each enrichment (avoid double-counting
// if there are multiple patch lines for the same key)
const seenAcars    = new Set();
const seenLibacars = new Set();
const seenApi      = new Set();

for (const line of lines) {
  try {
    const event = JSON.parse(line);
    validJson++;

    if (event._patch) {
      // Patch line – only update enrichment counters
      const k = event._key || '__unknown__';
      if (event.acars_decoded?.ok  && !seenAcars.has(k))    { acarsDecodedCount++;    seenAcars.add(k); }
      if (event.libacars?.ok       && !seenLibacars.has(k)) { libacarsDecodedCount++; seenLibacars.add(k); }
      if (event.airframes_api      && !seenApi.has(k))      { apiCachedCount++;       seenApi.add(k); }
      continue;
    }

    // Base line
    const label     = event.label     || event.raw?.label     || 'unknown';
    const source    = event.source    || event.raw?.source    || 'unknown';
    const timestamp = event.timestamp || event.raw?.timestamp;

    // Enrich counters on base lines too (older files pre-patch-strategy)
    const k = event.id || (event.timestamp + '-' + event.station + '-' + event.text);
    if (event.acars_decoded?.ok  && !seenAcars.has(k))    { acarsDecodedCount++;    seenAcars.add(k); }
    if (event.libacars?.ok       && !seenLibacars.has(k)) { libacarsDecodedCount++; seenLibacars.add(k); }
    if (event.airframes_api      && !seenApi.has(k))      { apiCachedCount++;       seenApi.add(k); }

    byLabel[label]   = (byLabel[label]  || 0) + 1;
    bySource[source] = (bySource[source]|| 0) + 1;

    if (timestamp) {
      if (!latestTimestamp   || timestamp > latestTimestamp)   latestTimestamp   = timestamp;
      if (!earliestTimestamp || timestamp < earliestTimestamp) earliestTimestamp = timestamp;
    }
  } catch (_) { invalidJson++; }
}

msg.headers = { 'content-type':'application/json; charset=utf-8', 'cache-control':'no-store' };
msg.payload = JSON.stringify({
  file:                  '/mnt/nfs_client/airframes-node-red/acarsdb',
  messages:             validJson - (seenAcars.size + seenLibacars.size + seenApi.size - Object.keys(byLabel).reduce((a,k)=>a+byLabel[k],0) < 0 ? 0 : 0),
  // simple: count only base lines
  base_lines:           Object.values(byLabel).reduce((a, v) => a + v, 0),
  patch_lines:          validJson - Object.values(byLabel).reduce((a, v) => a + v, 0),
  valid_json:           validJson,
  invalid_json:         invalidJson,
  acars_decoded_count:  acarsDecodedCount,
  libacars_decoded_count: libacarsDecodedCount,
  api_cached_count:     apiCachedCount,
  earliest_timestamp:   earliestTimestamp,
  latest_timestamp:     latestTimestamp,
  by_label:             byLabel,
  by_source:            bySource
});
return msg;

const icao = String(msg.req?.params?.icao||'').trim().toUpperCase();
if (!/^[A-F0-9]{6}$/.test(icao)) {
  msg.statusCode = 400;
  msg.headers    = { 'content-type':'application/json; charset=utf-8' };
  msg.payload    = { error:'invalid_icao', icao };
  return [null, msg];
}
msg.url = 'https://api.airframes.io/airframes/icao/' + encodeURIComponent(icao);
msg.method  = 'GET';
msg.headers = { 'accept':'application/json; x-api-key: ' };
return [msg, null];

msg.headers = { 'content-type':'application/json; charset=utf-8', 'cache-control':'no-store' };
if (msg.statusCode && msg.statusCode >= 400) {
  msg.payload = { error:'airframes_api_error', statusCode:msg.statusCode, response:msg.payload };
}
return msg;
